class Solution {
public:
    string smallestSubsequence(string s) {
        int last[26] = {0};
        for (int i = 0; i < s.size(); i++) {
            last[s[i] - 'a'] = i;
        }
        string res;
        bool used[26] = {false};
        for (int i = 0; i < s.size(); i++) {
            if (used[s[i] - 'a']) continue;
            while (res.size() && res.back() > s[i] && i < last[s.back() - 'a']) {
                used[res.back() - 'a'] = false;
                res.pop_back();
            }
            res.push_back(s[i]);
            used[s[i] - 'a'] = true;
        }
        return res;
    }
};
```
